import json
import re

# Get the stored result - it seems to be directly available
businesses = locals().get('var_functions.query_db:36', [])

print('Type of businesses data:', type(businesses))
print('Number of businesses:', len(businesses) if isinstance(businesses, list) else 'Not a list')

if isinstance(businesses, list) and len(businesses) > 0:
    # Extract state and review count per business
    state_reviews = {}
    businesses_per_state = {}
    business_state_map = {}

    print('\nProcessing businesses...')
    for biz in businesses:
        desc = biz.get('description', '')
        business_id = biz.get('business_id', '')
        try:
            review_count = int(biz.get('review_count', 0))
        except:
            review_count = 0

        # Extract state abbreviation from description (look for pattern: ', XX' or 'in XX')
        match = re.search(r', ([A-Z]{2})\b', desc)
        if not match:
            match = re.search(r'\bin\s+([A-Z]{2})\b', desc)

        if match:
            state = match.group(1)
            state_reviews[state] = state_reviews.get(state, 0) + review_count
            businesses_per_state[state] = businesses_per_state.get(state, 0) + 1
            business_state_map[business_id] = state
            print(f'  {business_id} -> {state}: {review_count} reviews')
        else:
            print(f'  {business_id} -> NO STATE FOUND in: {desc[:60]}...')

    print('\nState review totals:')
    for state, count in state_reviews.items():
        print(f'  {state}: {count} reviews ({businesses_per_state[state]} businesses)')

    if state_reviews:
        top_state = max(state_reviews, key=state_reviews.get)
        result = {
            'top_state': top_state,
            'top_state_reviews': state_reviews[top_state],
            'top_state_businesses': businesses_per_state[top_state],
            'all_states': state_reviews,
            'business_count': len(businesses)
        }
    else:
        result = {'error': 'No state information found'}
else:
    result = {'error': 'No business data available', 'data': businesses}

print('\n__RESULT__:')
print(json.dumps(result))

