import re

# Get all businesses
businesses = locals().get('var_functions.query_db:62', [])
print('Businesses loaded:', len(businesses))

# Extract state and aggregate review counts
state_data = {}

for biz in businesses:
    desc = biz.get('description', '')
    biz_id = biz.get('business_id', '')
    review_count = int(biz.get('review_count', 0))

    # Extract 2-letter state code
    match = re.search(r',\s*([A-Z]{2})\b', desc)
    if not match:
        match = re.search(r'\bin\s+([A-Z]{2})\b', desc)

    if match:
        state = match.group(1)
        if state not in state_data:
            state_data[state] = {'total_reviews': 0, 'business_ids': []}
        state_data[state]['total_reviews'] += review_count
        state_data[state]['business_ids'].append(biz_id)

# Find top state
if state_data:
    top_state = max(state_data, key=lambda x: state_data[x]['total_reviews'])
    result = {
        'top_state': top_state,
        'top_state_data': state_data[top_state],
        'all_states_count': len(state_data)
    }
else:
    result = {'error': 'no state data found'}

print('__RESULT__:')
print(json.dumps(result))

